import React, { useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #1a3a5c 0%, #2980b9 100%)', padding: 24 },
  card: { background: '#fff', borderRadius: 16, padding: '36px', width: 440, boxShadow: '0 20px 60px rgba(0,0,0,0.3)' },
  title: { textAlign: 'center', fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 24 },
  grid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 },
  label: { display: 'block', fontSize: 13, fontWeight: 600, color: '#444', marginBottom: 5 },
  input: { width: '100%', padding: '10px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, outline: 'none' },
  full: { gridColumn: '1/-1' },
  btn: { width: '100%', padding: '12px', background: '#1a3a5c', color: '#fff', border: 'none', borderRadius: 8, fontSize: 16, fontWeight: 700, cursor: 'pointer', marginTop: 20 },
  err: { background: '#fdecea', color: '#c0392b', padding: '10px', borderRadius: 8, fontSize: 14, marginBottom: 14, gridColumn: '1/-1' },
  linkRow: { textAlign: 'center', marginTop: 18, fontSize: 14, color: '#666' }
};

export default function Register() {
  const [form, setForm] = useState({ name: '', usn: '', email: '', mobile: '', password: '', address: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      const { data } = await axios.post('/api/auth/register', form);
      login(data);
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
    }
    setLoading(false);
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <div style={s.title}>🚌 Student Registration</div>
        <form onSubmit={handleSubmit}>
          <div style={s.grid}>
            {error && <div style={s.err}>{error}</div>}
            <div><label style={s.label}>Full Name</label><input style={s.input} value={form.name} onChange={set('name')} required placeholder="Prajwal K" /></div>
            <div><label style={s.label}>USN</label><input style={s.input} value={form.usn} onChange={set('usn')} required placeholder="4NI23CS146" /></div>
            <div><label style={s.label}>Email</label><input style={s.input} type="email" value={form.email} onChange={set('email')} required placeholder="you@nie.ac.in" /></div>
            <div><label style={s.label}>Mobile</label><input style={s.input} value={form.mobile} onChange={set('mobile')} required placeholder="9876543210" /></div>
            <div><label style={s.label}>Password</label><input style={s.input} type="password" value={form.password} onChange={set('password')} required /></div>
            <div style={s.full}><label style={s.label}>Address</label><input style={s.input} value={form.address} onChange={set('address')} placeholder="Your home address" /></div>
          </div>
          <button style={s.btn} disabled={loading}>{loading ? 'Registering...' : 'Register'}</button>
        </form>
        <div style={s.linkRow}>Already have an account? <Link to="/login" style={{ color: '#2980b9', fontWeight: 600 }}>Login</Link></div>
      </div>
    </div>
  );
}
